const question = $.input.question || '';
const context = $.input.conversationContext || '';
const role = $.input.systemRole || 'helpful assistant';
const userName = $.input.userName || 'User';
const now = new Date().toLocaleString('en-US', { dateStyle: 'full', timeStyle: 'short' });

let prompt = 'You are a ' + role + '. You have memory of previous conversations and should use this context to provide better, more personalized responses.\n\n';
prompt += 'CURRENT DATE/TIME: ' + now + '\n';
prompt += 'USER NAME: ' + userName + '\n\n';

if (context) {
  prompt += 'CONVERSATION MEMORY / CONTEXT:\n';
  prompt += context + '\n\n';
  prompt += 'Use the above context to inform your response. Reference previous topics when relevant. Show that you remember prior conversations.\n\n';
}

prompt += 'CURRENT QUESTION FROM ' + userName + ':\n' + question + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer the question thoughtfully and completely\n';
prompt += '- If context is provided, reference it naturally (do not just summarize the context)\n';
prompt += '- If the question relates to a previous conversation topic, build upon it\n';
prompt += '- Be conversational and engaging\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, ```code```, numbered lists\n';
prompt += '- Keep response focused and useful\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "response": "your complete response using Slack mrkdwn formatting",\n';
prompt += '  "memoryUpdate": "brief summary of this exchange to add to memory for future context (1-2 sentences)",\n';
prompt += '  "topicTags": ["topic1", "topic2"],\n';
prompt += '  "followUpSuggestions": ["natural follow-up question 1", "question 2"],\n';
prompt += '  "usedContext": true,\n';
prompt += '  "responseType": "answer|explanation|suggestion|creative|code|analysis"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiChat.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { response: raw, memoryUpdate: '', topicTags: [], followUpSuggestions: [], usedContext: false, responseType: 'answer' }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const userName = $.input.userName || 'User';
const hasContext = $.input.conversationContext ? true : false;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Chat Response', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + userName + ' asked:* ' + question.slice(0, 500) } });

const contextIndicator = hasContext ? ':brain: _Using conversation memory_' : ':new: _New conversation_';
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: contextIndicator + ' | Type: ' + (ai.responseType || 'answer') }] });

blocks.push({ type: 'divider' });

const response = (ai.response || 'No response generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: response } });

if (ai.memoryUpdate) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':floppy_disk: *Memory Update:* ' + ai.memoryUpdate } });
}

if (ai.followUpSuggestions && ai.followUpSuggestions.length > 0) {
  blocks.push({ type: 'divider' });
  let fqText = '*Suggested Follow-ups:*\n';
  ai.followUpSuggestions.forEach((q, i) => { fqText += (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fqText.slice(0, 1800) } });
}

if (ai.topicTags && ai.topicTags.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Topics: ' + ai.topicTags.join(', ') + ' | Powered by Claude AI | One CLI' }] });
} else {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI | One CLI' }] });
}

const fallbackText = 'AI Chat: ' + (ai.response || '').slice(0, 100);
return { blocks, fallbackText, memoryUpdate: ai.memoryUpdate || '' };
